INSERT INTO public.posts (title, slug, excerpt, content, cover_image, is_published, published_at, views_count) VALUES
('Xu hướng giá BĐS Việt Nam 2025-2026', 'xu-huong-gia-bds-vn', 'Phân tích xu hướng giá BĐS tại TP.HCM và Hà Nội.', '<h2>Tổng quan</h2><p>Thị trường BĐS phục hồi mạnh. Giá tăng 8-15%.</p><h2>TP.HCM</h2><p>Căn hộ 45-80 triệu/m2.</p><h2>Hà Nội</h2><p>Tăng trưởng ổn định.</p>', 'https://images.unsplash.com/photo-1560518883-ce09059eeffa?w=1200', true, '2026-04-01 10:00:00+07', 3421),
('Hướng dẫn mua nhà lần đầu', 'huong-dan-mua-nha-lan-dau', 'Từ xác định ngân sách đến ký hợp đồng.', '<h2>1. Ngân sách</h2><p>Vay không quá 50% thu nhập.</p><h2>2. Khu vực</h2><p>Gần nơi làm việc.</p><h2>3. Pháp lý</h2><p>Kiểm tra sổ hồng.</p>', 'https://images.unsplash.com/photo-1582407947304-fd86f028f716?w=1200', true, '2026-03-30 10:00:00+07', 2876),
('So sánh chung cư và nhà phố', 'so-sanh-chung-cu-nha-pho', 'Ưu nhược điểm giúp chọn loại hình phù hợp.', '<h2>Chung cư</h2><p>An ninh, tiện ích.</p><h2>Nhà phố</h2><p>Sở hữu đất, tự do thiết kế.</p>', 'https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=1200', true, '2026-03-28 10:00:00+07', 4102),
('Top 10 dự án BĐS TP.HCM 2025', 'top-du-an-bds-tphcm-2025', '10 dự án nổi bật TP.HCM.', '<h2>1. Vinhomes Grand Park</h2><p>271ha, 2.5-8 tỷ.</p><h2>2. Masteri Centre Point</h2><p>3.5-6 tỷ.</p>', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=1200', true, '2026-03-26 10:00:00+07', 5234),
